function prtfl_echo_nonce () {
	echo sprintf(
		'<input type="hidden" name="%1$s" id="%1$s" value="%2$s" />',
		'prtfl_nonce_name',
		wp_create_nonce( plugin_basename(__FILE__) )
	);
}

