	$invoiceItemsTotalTax = 0;

	while($row = $res->fetchRow(DB_FETCHMODE_ASSOC)) {

		$invoice_items .= "". 
			"<tr>".
				"<td>".$row['planName']."</td>".
				"<td>".$row['amount']."</td>".
				"<td>".$row['tax_amount']."</td>".
				"<td>".$row['notes']."</td>".
			"</tr>";

		// populate invoice items - NEW STYLE
		$invoiceItem = array();

